------------------------------------------------------------------ -- Normalize process.keyword → log.process.keyword (SAFE) ------------------------------------------------------------------- UPDATE utm_visualization SET filters = REPLACE(filters, '"field":"process.keyword"', '"field":"log.process.keyword"') WHERE filters LIKE '%"field":"process.keyword"%';
UPDATE utm_visualization SET aggregation = REPLACE(aggregation, '"field":"process.keyword"', '"field":"log.process.keyword"') WHERE aggregation LIKE '%"field":"process.keyword"%';
------------------------------------------------------------------ -- Normalize level.keyword → log.level.keyword (SAFE) ------------------------------------------------------------------- UPDATE utm_visualization SET filters = REPLACE(filters, '"field":"level.keyword"', '"field":"log.level.keyword"') WHERE filters LIKE '%"field":"level.keyword"%';
UPDATE utm_visualization SET aggregation = REPLACE(aggregation, '"field":"level.keyword"', '"field":"log.level.keyword"') WHERE aggregation LIKE '%"field":"level.keyword"%';
